const payload = (typeof msg.payload === "object" && msg.payload !== null) ? msg.payload : {};
const deviceId = String(payload.device_id || "").trim();

if (!deviceId) {
    node.warn("Mensaje descartado: falta device_id");
    return null;
}

const co = Number(payload.co_ppm);
if (!Number.isFinite(co)) {
    node.warn(`Mensaje descartado (${deviceId}): co_ppm invalido`);
    return null;
}

const rawPresencia = payload.presencia;
const presencia =
    rawPresencia === true ||
    rawPresencia === 1 ||
    rawPresencia === "1" ||
    String(rawPresencia || "").toUpperCase() === "SI" ||
    String(rawPresencia || "").toLowerCase() === "true";

let estadoBase = "SEGURO";
if (co < 10) estadoBase = "SEGURO";
else if (co < 15) estadoBase = "PRECAUCION";
else if (co < 30) estadoBase = "PELIGRO";
else estadoBase = "CRITICO";

const urgente = presencia && co >= 30;
const estado = urgente ? `${estadoBase}_URGENTE` : estadoBase;

const timestamp =
    (typeof payload.timestamp === "string" && payload.timestamp.trim().length > 0)
        ? payload.timestamp
        : new Date().toISOString();

msg.telemetry = {
    device_id: deviceId,
    node_type: "unknown",
    timestamp,
    co_ppm: Number(co.toFixed(1)),
    presencia,
    presencia_text: presencia ? "SI" : "NO",
    estado,
    estado_base: estadoBase,
    urgente,
    source_topic: msg.topic || "",
    message_id: payload.message_id ?? null
};

msg.payload = msg.telemetry;
return msg;

const t = msg.telemetry;
msg.topic = "INSERT INTO devices (device_id, node_type, description, last_seen_at) VALUES (?, ?, ?, NOW(3)) ON DUPLICATE KEY UPDATE node_type=VALUES(node_type), description=VALUES(description), last_seen_at=NOW(3)";
msg.payload = [t.device_id, t.node_type, `${t.node_type} node`];
return msg;

const t = msg.telemetry;
msg.topic = "INSERT INTO sensor_readings (device_id, device_timestamp, co_ppm, presencia, source_topic, message_id) VALUES (?, ?, ?, ?, ?, ?)";
msg.payload = [t.device_id, t.timestamp, t.co_ppm, t.presencia ? 1 : 0, t.source_topic, t.message_id];
return msg;

const t = msg.telemetry;
const reason = t.urgente
  ? "Presencia detectada durante nivel crítico de CO"
  : `Clasificación por umbral: ${t.estado_base}`;

msg.topic = "INSERT INTO state_events (device_id, device_timestamp, estado, urgente, co_ppm, presencia, reason) VALUES (?, ?, ?, ?, ?, ?, ?)";
msg.payload = [t.device_id, t.timestamp, t.estado, t.urgente ? 1 : 0, t.co_ppm, t.presencia ? 1 : 0, reason];
return msg;

const t = msg.telemetry;

if (!(t.urgente || t.co_ppm >= 30)) {
  return null;
}

const severity = t.urgente ? "CRITICAL" : "HIGH";
const alertType = t.urgente ? "CRITICO_URGENTE" : "CO_CRITICO";
const message = t.urgente
  ? "CO crítico con presencia detectada."
  : "CO crítico sin presencia detectada.";

msg.alertPayload = {
  device_id: t.device_id,
  timestamp: t.timestamp,
  severity,
  alert_type: alertType,
  message,
  co_ppm: t.co_ppm,
  presencia: t.presencia ? "SI" : "NO",
  estado: t.estado
};

msg.topic = "INSERT INTO alerts (device_id, device_timestamp, severity, alert_type, message, co_ppm, presencia, urgente) VALUES (?, ?, ?, ?, ?, ?, ?, ?)";
msg.payload = [t.device_id, t.timestamp, severity, alertType, message, t.co_ppm, t.presencia ? 1 : 0, t.urgente ? 1 : 0];
return msg;

if (!msg.alertPayload) {
  return null;
}

const topicBase = env.get("MQTT_TOPIC_BASE") || "your_maqiatto_username/fiot/garage";
msg.topic = `${topicBase}/alerts/${msg.alertPayload.device_id}`;
msg.payload = msg.alertPayload;
return msg;

const simId = env.get("SIM_DEVICE_ID") || "SIM-GARAGE-CO-001";
const topicBase = env.get("MQTT_TOPIC_BASE") || "your_maqiatto_username/fiot/garage";
const co = Number((6 + Math.random() * 39).toFixed(1));
const presencia = Math.random() > 0.55;

let estado = "SEGURO";
if (co < 10) estado = "SEGURO";
else if (co < 15) estado = "PRECAUCION";
else if (co < 30) estado = "PELIGRO";
else estado = "CRITICO";

if (presencia && co >= 30) {
  estado += "_URGENTE";
}

msg.topic = `${topicBase}/${simId}/telemetry`;
msg.payload = {
  device_id: simId,
  timestamp: new Date().toISOString(),
  co_ppm: co,
  presencia: presencia ? "SI" : "NO",
  estado
};

return msg;
